import{_ as e,o as d,c as a,ag as r}from"./chunks/framework.OsDJF_Ea.js";const u=JSON.parse('{"title":"Integrations","description":"Configuration reference for all Krado One integrations — JIRA, Slack, n8n, OpenAI, GitHub, ArgoCD, and more.","frontmatter":{"title":"Integrations","description":"Configuration reference for all Krado One integrations — JIRA, Slack, n8n, OpenAI, GitHub, ArgoCD, and more."},"headers":[],"relativePath":"admin/integrations.md","filePath":"admin/integrations.md"}'),o={name:"admin/integrations.md"};function n(i,t,h,s,c,l){return d(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="integrations" tabindex="-1">Integrations <a class="header-anchor" href="#integrations" aria-label="Permalink to &quot;Integrations&quot;">​</a></h1><p>All integrations can be configured via <strong>Portal Config → Integrations</strong> or via environment variables. Environment variables seed the database on first startup; once saved through the UI the database value takes precedence.</p><hr><h2 id="jira" tabindex="-1">JIRA <a class="header-anchor" href="#jira" aria-label="Permalink to &quot;JIRA&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Env var</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>JIRA_URL</code></td><td>Yes</td><td>Atlassian base URL, e.g. <code>https://acme.atlassian.net</code></td></tr><tr><td><code>JIRA_EMAIL</code></td><td>Yes</td><td>Service account email</td></tr><tr><td><code>JIRA_API_TOKEN</code></td><td>Yes</td><td>Atlassian API token</td></tr></tbody></table><p><strong>Portal Config tab:</strong> Productivity → JIRA</p><hr><h2 id="slack" tabindex="-1">Slack <a class="header-anchor" href="#slack" aria-label="Permalink to &quot;Slack&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Env var</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>SLACK_BOT_TOKEN</code></td><td>Yes</td><td><code>xoxb-...</code> bot OAuth token</td></tr><tr><td><code>SLACK_WEBHOOK_URL</code></td><td>No</td><td>Incoming webhook for notifications</td></tr><tr><td><code>SLACK_SCAN_CHANNEL_IDS</code></td><td>No</td><td>Comma-separated channel IDs to scan</td></tr><tr><td><code>SLACK_MENTION_USER_ID</code></td><td>No</td><td>User ID to @mention in alerts</td></tr></tbody></table><p><strong>Portal Config tab:</strong> Productivity → Slack</p><hr><h2 id="n8n" tabindex="-1">n8n <a class="header-anchor" href="#n8n" aria-label="Permalink to &quot;n8n&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Env var</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>N8N_URL</code></td><td>Yes</td><td>n8n base URL, e.g. <code>http://n8n:5678</code></td></tr><tr><td><code>N8N_API_KEY</code></td><td>Yes</td><td>n8n API key</td></tr></tbody></table><p><strong>Portal Config tab:</strong> Productivity → n8n</p><hr><h2 id="openai-ai-assistant" tabindex="-1">OpenAI (AI Assistant) <a class="header-anchor" href="#openai-ai-assistant" aria-label="Permalink to &quot;OpenAI (AI Assistant)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Env var</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>OPENAI_API_KEY</code></td><td>Yes</td><td>OpenAI API key (<code>sk-...</code>)</td></tr><tr><td><code>OPENAI_MODEL</code></td><td>No</td><td>Model ID, default <code>gpt-4o</code></td></tr><tr><td><code>OPENAI_SYSTEM_PROMPT</code></td><td>No</td><td>Override the default system prompt</td></tr></tbody></table><p><strong>Portal Config tab:</strong> AI</p><hr><h2 id="github" tabindex="-1">GitHub <a class="header-anchor" href="#github" aria-label="Permalink to &quot;GitHub&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Env var</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>GITHUB_ORG</code></td><td>Yes</td><td>GitHub organization name</td></tr><tr><td><code>GITHUB_PAT</code></td><td>Yes</td><td>Personal access token with <code>repo</code> and <code>read:org</code> scopes</td></tr></tbody></table><p><strong>Portal Config tab:</strong> Developer Tools → GitHub</p><hr><h2 id="terraform-cloud" tabindex="-1">Terraform Cloud <a class="header-anchor" href="#terraform-cloud" aria-label="Permalink to &quot;Terraform Cloud&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Env var</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>TERRAFORM_ORG</code></td><td>Yes</td><td>Terraform Cloud organization</td></tr><tr><td><code>TERRAFORM_API_TOKEN</code></td><td>Yes</td><td>Terraform Cloud API token</td></tr><tr><td><code>TERRAFORM_WORKSPACE_PREFIX</code></td><td>No</td><td>Filter workspaces by prefix</td></tr></tbody></table><p><strong>Portal Config tab:</strong> Developer Tools → Terraform</p><hr><h2 id="argocd" tabindex="-1">ArgoCD <a class="header-anchor" href="#argocd" aria-label="Permalink to &quot;ArgoCD&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Env var</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>ARGOCD_URL</code></td><td>Yes</td><td>ArgoCD server URL</td></tr><tr><td><code>ARGOCD_API_TOKEN</code></td><td>Yes</td><td>ArgoCD API token</td></tr></tbody></table><p><strong>Portal Config tab:</strong> Observability → ArgoCD</p><hr><h2 id="pagerduty" tabindex="-1">PagerDuty <a class="header-anchor" href="#pagerduty" aria-label="Permalink to &quot;PagerDuty&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Env var</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>PAGERDUTY_API_KEY</code></td><td>Yes</td><td>PagerDuty REST API key</td></tr></tbody></table><p><strong>Portal Config tab:</strong> Observability → PagerDuty</p><hr><h2 id="prometheus" tabindex="-1">Prometheus <a class="header-anchor" href="#prometheus" aria-label="Permalink to &quot;Prometheus&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Env var</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>PROMETHEUS_URL</code></td><td>Yes</td><td>Prometheus base URL, e.g. <code>http://prometheus:9090</code></td></tr></tbody></table><p><strong>Portal Config tab:</strong> Observability → Prometheus</p><hr><h2 id="google-calendar" tabindex="-1">Google Calendar <a class="header-anchor" href="#google-calendar" aria-label="Permalink to &quot;Google Calendar&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Env var</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>GOOGLE_CALENDAR_ID</code></td><td>Yes</td><td>Calendar ID for maintenance events</td></tr><tr><td><code>GOOGLE_SERVICE_ACCOUNT_JSON</code></td><td>Yes</td><td>Service account JSON (base64 or path)</td></tr></tbody></table><p><strong>Portal Config tab:</strong> Google Calendar</p><hr><h2 id="cloud-providers" tabindex="-1">Cloud Providers <a class="header-anchor" href="#cloud-providers" aria-label="Permalink to &quot;Cloud Providers&quot;">​</a></h2><p>See <a href="./../portals/cloud/overview">Cloud Overview</a> for AWS, GCP, and Azure configuration.</p><hr><h2 id="smtp-email" tabindex="-1">SMTP (Email) <a class="header-anchor" href="#smtp-email" aria-label="Permalink to &quot;SMTP (Email)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Env var</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>SMTP_HOST</code></td><td>—</td><td>SMTP server hostname</td></tr><tr><td><code>SMTP_PORT</code></td><td><code>587</code></td><td>SMTP port</td></tr><tr><td><code>SMTP_USER</code></td><td>—</td><td>SMTP username</td></tr><tr><td><code>SMTP_PASSWORD</code></td><td>—</td><td>SMTP password</td></tr><tr><td><code>SMTP_FROM</code></td><td><code>noreply@devx.local</code></td><td>From address</td></tr></tbody></table>',48)])])}const g=e(o,[["render",n]]);export{u as __pageData,g as default};
